import sys

def solve(data: str) -> str:
    tokens = iter(data.split()); n = int(next(tokens)); rows = []
    for index in range(n):
        rows.append((float(next(tokens)), next(tokens), index))
    query = float(next(tokens))
    _, label, _ = min(rows, key=lambda row: (abs(row[0] - query), row[2]))
    return label

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
